   let j=await wikiQuery({action:'query',titles:key,redirects:'1',prop:'pageimages|info',inprop:'url',pithumbsize:'500'});
   let p=j.query?.pages?.[0];
   let result=p&&!p.missing?{image:p.thumbnail?.source,url:p.fullurl,title:p.title}:{};
   if(!result.url||!result.image){
     j=await wikiQuery({action:'query',generator:'search',gsrsearch:key,gsrnamespace:'0',gsrlimit:'6',prop:'pageimages|info',inprop:'url',pithumbsize:'500'});
     const pages=j.query?.pages||[];
     const best=pages.find(x=>x.thumbnail?.source)||pages[0];
     if(best)result={image:best.thumbnail?.source||result.image,url:best.fullurl||result.url,title:best.title};
   }
   if(!result.url)result.url=item.wiki;
   wikiCache.set(key,result);cb(result)
