 if(kind==='person')values=[...(active.has('movements')?(item.keywords||[]):[]),...DATA.works.filter(x=>x.authorId===item.id).map(x=>`${x.title} · ${x.year}`)];
 else if(kind==='work'){const a=DATA.people.find(x=>x.id===item.authorId);values=[...(active.has('movements')?(item.keywords||[]):[])];if(a)values.push(a.name,`${a.start}–${a.end}`);}
 else if(kind==='event')values=(item.categories||[]).map(x=>({"czech-history":"České dějiny","world-history":"Světové dějiny",war:'Válka',politics:'Politika',science:'Věda',invention:'Vynález',culture:'Kultura',literature:'Literatura',society:'Společnost',religion:'Náboženství'}[x]||x));
 else if(kind==='period')values=[item.scope==='world'?'Svět':'České země',`${item.end-item.start+1} let`];
